                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(noteOnString)))
                    {
                        return noteOnString!!
                    }
                }
                else 
                {
                    if (note.octave == -1.0 && note.tone == -1.0)
                    {
                        if (note.index < previousBeat!!.notes.length)
                        {
                            return previousBeat!!.notes[(note.index).toInt()]
                        }
                    }
                    else 
                    {
                        var noteWithValue: com.omnifret.gplayer.model.Note? = previousBeat!!.getNoteWithRealValue(note.realValue)
                        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(noteWithValue)))
                        {
                            return noteWithValue!!
                        }
                    }
                }
                previousBeat = previousBeat!!.previousBeat
            }
            return null
        }
        
        @kotlin.jvm.JvmStatic
        private var _noteIdLookupKey: String = "NoteIdLookup"
        
    }
    public constructor()
}

/**
 * Lists all graphical sub elements within a  which can be styled via 
 */
public enum class NoteSubElement(override val value: Int): com.omnifret.gplayer.core.IGPlayerEnum
{
    /**
     * The effects and annotations shown in dedicated effect bands above the staves (e.g. vibrato).
     * The style of the first note with the effect wins.
     */
    Effects(0),
    /**
     * The note head on the standard notation staff.
     */
    StandardNotationNoteHead(1),
    /**
     * The accidentals on the standard notation staff.
     */
    StandardNotationAccidentals(2),
    /**
     * The effects and annotations applied to this note on the standard notation staff (e.g. bends).
     * If effects on beats result in individual note elements shown, this color will apply.
     */
    StandardNotationEffects(3),
    /**
     * The fret number on the guitar tab staff.
     */
    GuitarTabFretNumber(4),
    /**
     * The effects and annotations applied to this note on the guitar tab staff (e.g. bends).
     * If effects on beats result in individual note elements shown, this color will apply.
     */
    GuitarTabEffects(5),
    /**
     * The note head on the slash notation staff.
     */
    SlashNoteHead(6),
    /**
     * The effects and annotations applied to this note on the slash notation staff (e.g. dots).
     * If effects on beats result in individual note elements shown, this color will apply.
     */
    SlashEffects(7),
    /**
     * The note number on the numbered notation staff.
     */
    NumberedNumber(8),
    /**
     * The accidentals on the numbered notation staff.
     */
    NumberedAccidentals(9),
    /**
     * The effects and annotations applied to this note on the number notation staff (e.g. dots).
     * If effects on beats result in individual note elements shown, this color will apply.
     */
    NumberedEffects(10);
    companion object : com.omnifret.gplayer.core.IGPlayerEnumCompanion<NoteSubElement>{
        public override val values = arrayOf(Effects, StandardNotationNoteHead, StandardNotationAccidentals, StandardNotationEffects, GuitarTabFretNumber, GuitarTabEffects, SlashNoteHead, SlashEffects, NumberedNumber, NumberedAccidentals, NumberedEffects) 
        public override fun fromValue(v:Double): NoteSubElement{
            return when(v.toInt()){
                Effects.value -> Effects
                StandardNotationNoteHead.value -> StandardNotationNoteHead
                StandardNotationAccidentals.value -> StandardNotationAccidentals
                StandardNotationEffects.value -> StandardNotationEffects
                GuitarTabFretNumber.value -> GuitarTabFretNumber
                GuitarTabEffects.value -> GuitarTabEffects
                SlashNoteHead.value -> SlashNoteHead
                SlashEffects.value -> SlashEffects
                NumberedNumber.value -> NumberedNumber
                NumberedAccidentals.value -> NumberedAccidentals
                NumberedEffects.value -> NumberedEffects
                else -> throw ClassCastException("No enum with value $v found")}
        }
    }
}

